import { Component, ViewChild } from '@angular/core';
import { FormGroup, FormBuilder, Validators, FormControl } from '@angular/forms';
import { MatPaginator } from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import { Page } from '@pages/page/page-list/page-list.component';
import { ApiService } from '@services/api.service';
import { tap, delay, merge, startWith, switchMap, map } from 'rxjs';

@Component({
  selector: 'app-claim-store-list',
  templateUrl: './claim-store-list.component.html',
  styleUrls: ['./claim-store-list.component.scss']
})
export class ClaimStoreListComponent {
  query: string = "";
  filterForm: FormGroup;
  isLoadingResults = true;

  displayedColumns: string[] = ['claim_store_id', 'store_name', 'user_name', 'claim_status', 'date',  'Action'];
  data : any[] = [];
  resultsLength = 0;
  sortBy: string = 'claim_store_id'

  claimStatuses = new FormControl('');
  claimStatusList: string[] = ['new', 'pending', 'accepted', 'rejected'];
  

  @ViewChild(MatPaginator) paginator: MatPaginator;
  @ViewChild(MatSort) sort: MatSort;


  constructor(private api: ApiService, private fb: FormBuilder) {
    this.filterForm = this.fb.group({
      q: ['', []],
      claim_status: [null, []]
    })

    this.filterForm.valueChanges.pipe(
      tap(() => this.isLoadingResults = true),
      delay(1000)
    ).subscribe(() => {
      this.api.getClaimStoreList(this.query, this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction, this.filterForm.value.claim_status).subscribe((data: any) => {
        this.isLoadingResults = false;
        // Flip flag to show that loading has finished.
        if (data === null) {
          return [];
        }

        this.resultsLength = data.total_count;
        this.data = data.claim_stores;
      })
    })
  }

  ngAfterViewInit() {
    this.sort.sortChange.subscribe(() => {
      this.paginator.pageIndex = 0
    });

    merge(this.sort.sortChange, this.paginator.page)
      .pipe(
        startWith({}),
        switchMap(() => {
          this.isLoadingResults = true;
          return this.api.getClaimStoreList(this.query, this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction, this.filterForm.value.claim_status);
        }),
        map((data: any) => {
          this.isLoadingResults = false;
          // Flip flag to show that loading has finished.
          if (data === null) {
            return [];
          }

          this.resultsLength = data.total_count;
          return data.claim_stores;
          
        }),
      )
      .subscribe(data => this.data = data);

  }
}
