import { Component } from '@angular/core';
import { FormGroup, FormBuilder, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from '@services/api.service';
import { ToastrService } from 'ngx-toastr';
import { catchError } from 'rxjs';

@Component({
  selector: 'app-claim-store-details',
  templateUrl: './claim-store-details.component.html',
  styleUrls: ['./claim-store-details.component.scss']
})
export class ClaimStoreDetailsComponent {
  claimStoreId: string;
  isLoading: boolean = true;

  claimDetails: any;

  constructor(
    private api: ApiService, 
    private route: ActivatedRoute,
    private toastr: ToastrService,
    private fb: FormBuilder,
    private router: Router
    ){
    this.route.params.subscribe((p: any) => {
      this.claimStoreId = p.claim_store_id;
      this.getClaimStoreDetails()
    })
  }

  ngOnInit() {
    
  }

  getClaimStoreDetails() {
    const sub = this.api.getClaimStoreDetails(this.claimStoreId)
    .pipe(
      catchError(err => err)
    )
    .subscribe((response: any) => {
      sub.unsubscribe();
      if(response.state > 400) {
        this.toastr.error(response.error.message)
        return
      }

      this.isLoading = false;
      this.claimDetails = response.claim_store;
    })
  }

  approveClaim() {
    const sub = this.api.approveStoreClaim(this.claimStoreId).subscribe((response: any) => {
      sub.unsubscribe();
      this.toastr.success(response.message)
      this.router.navigate(['/claim'])
    })
  }

  declineClaim() {
    const sub = this.api.declineStoreClaim(this.claimStoreId).subscribe((response: any) => {
      sub.unsubscribe();
      this.toastr.success(response.message)
      this.router.navigate(['/claim'])
    })
  }

  deleteClaim() {
    const sub = this.api.deleteStoreClaim(this.claimStoreId).subscribe((response: any) => {
      sub.unsubscribe();
      this.toastr.success(response.message)
      this.router.navigate(['/claim'])
    })
  }
  
}
