import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { ClaimStoreDetailsComponent } from './claim-store-details/claim-store-details.component';
import { ClaimStoreListComponent } from './claim-store-list/claim-store-list.component';

const routes: Routes = [
  {path: '', component: ClaimStoreListComponent},
  {path: 'details/:claim_store_id', component: ClaimStoreDetailsComponent}
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class ClaimStoreRoutingModule { }
